import{_ as r}from"./chunks/macro_lfo_param.CHH6zHzC.js";import{_ as o,C as d,o as s,c as n,a3 as i,E as l,w as m,j as t}from"./chunks/framework.BSbon55W.js";const O=JSON.parse('{"title":"S32 LFO Parameter","description":"","frontmatter":{"title":"S32 LFO Parameter","pageClass":"macro-doc"},"headers":[],"relativePath":"macros/s32-lfo-parameter.md","filePath":"macros/s32-lfo-parameter.md"}'),h={name:"macros/s32-lfo-parameter.md"};function c(p,e,u,f,g,b){const a=d("ManualRelated");return s(),n("div",null,[e[1]||(e[1]=i('<h1 id="s32-lfo-parameter" tabindex="-1">S32 LFO Parameter <a class="header-anchor" href="#s32-lfo-parameter" aria-label="Permalink to &quot;S32 LFO Parameter&quot;">​</a></h1><p><strong>Firmware menu name:</strong> S32 LFO</p><p>Modulate a global S32 LFO parameter.</p><p><img src="'+r+'" alt="S32 LFO Parameter macro" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Use <strong>S32 LFO</strong> to modulate one of the <strong>16 global S32 LFOs</strong> (rate, depth, sync, wavetable, phase, offset) from a knob — ideal for performance control of modulation depth or speed.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Mode</td><td>—</td><td>Macro output type. Change this to switch between MIDI, internal routing, and CV16 targets.</td></tr><tr><td>LFO Index</td><td>LFO 1 – 16</td><td>Which CV16 or S32 LFO is modulated (depends on macro mode).</td></tr><tr><td>CV Param.</td><td>LFO parameter</td><td>Which LFO field the knob adjusts. Available options depend on <strong>S32 LFO</strong> vs <strong>CV16 LFO</strong> mode.</td></tr><tr><td>Minimum</td><td>Mode-specific</td><td>Value sent when the knob is at minimum travel. Units follow the target (MIDI 0–127, 14-bit 0–16383, device parameter native range, CV volts, LFO %, etc.).</td></tr><tr><td>Maximum</td><td>Mode-specific</td><td>Value sent when the knob is at maximum travel. Must be greater than or equal to <strong>Minimum</strong>.</td></tr><tr><td>Invert</td><td>True / False</td><td>When <strong>True</strong>, knob clockwise motion maps to decreasing values (minimum ↔ maximum swapped).</td></tr></tbody></table></div><h2 id="s32-lfo-parameters-you-can-target" tabindex="-1">S32 LFO parameters you can target <a class="header-anchor" href="#s32-lfo-parameters-you-can-target" aria-label="Permalink to &quot;S32 LFO parameters you can target&quot;">​</a></h2><p>When <strong>Parameter</strong> (CV Param.) is set, these are the LFO fields available in <strong>S32 LFO</strong> macro mode:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>What it does</th></tr></thead><tbody><tr><td>Enabled</td><td>Turn the target LFO on or off.</td></tr><tr><td>Wavetable</td><td>LFO waveform shape.</td></tr><tr><td>Rate</td><td>LFO speed (sync divisions or Hz depending on LFO sync setting).</td></tr><tr><td>Sync</td><td>Lock LFO rate to MIDI clock.</td></tr><tr><td>Depth</td><td>Modulation depth (0–100%).</td></tr><tr><td>Offset</td><td>DC offset added to the LFO (-100 – +100%).</td></tr><tr><td>Phase</td><td>Start position in the cycle (0–360°).</td></tr></tbody></table>',11)),l(a,{title:"Related topics"},{default:m(()=>[...e[0]||(e[0]=[t("ul",null,[t("li",null,[t("a",{href:"/versions/v0.12.0/macros/"},"Macros overview")]),t("li",null,[t("a",{href:"/versions/v0.12.0/macros/setting-up-macros"},"Setting up macros")]),t("li",null,[t("a",{href:"/versions/v0.12.0/concepts/modulation"},"Modulation")])],-1)])]),_:1})])}const v=o(h,[["render",c]]);export{O as __pageData,v as default};
